package com.oyuki.complaint.controller;
import com.oyuki.complaint.entity.Complaint; import com.oyuki.complaint.enums.ComplaintStatus; import com.oyuki.complaint.repository.ComplaintRepository; import com.oyuki.user.repository.UserRepository; import org.springframework.http.*; import org.springframework.security.core.Authentication; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/complaints") public class ComplaintController { private final ComplaintRepository repo; private final UserRepository users; public ComplaintController(ComplaintRepository r,UserRepository u){repo=r;users=u;} @PostMapping public ResponseEntity<?> create(Authentication a,@RequestBody Map<String,Object> b){Long uid=(Long)a.getPrincipal(); Complaint c=Complaint.builder().customer(users.findById(uid).orElseThrow()).subject(String.valueOf(b.getOrDefault("subject","Complaint"))).message(String.valueOf(b.getOrDefault("message",""))).orderId(b.get("orderId")==null?null:Long.valueOf(String.valueOf(b.get("orderId")))).build(); return ResponseEntity.status(HttpStatus.CREATED).body(map(repo.save(c)));} @GetMapping("/my") public List<Map<String,Object>> mine(Authentication a){return repo.findAllByCustomer_IdOrderByCreatedAtDesc((Long)a.getPrincipal()).stream().map(this::map).toList();} @GetMapping("/admin") public List<Map<String,Object>> all(){return repo.findAllByOrderByCreatedAtDesc().stream().map(this::map).toList();} @PatchMapping("/admin/{id}") public Map<String,Object> update(@PathVariable Long id,@RequestBody Map<String,String>b){Complaint c=repo.findById(id).orElseThrow(); if(b.get("status")!=null)c.setStatus(ComplaintStatus.valueOf(b.get("status"))); c.setResolution(b.get("resolution")); return map(repo.save(c));} private Map<String,Object> map(Complaint c){Map<String,Object>m=new LinkedHashMap<>();m.put("id",c.getId());m.put("customerId",c.getCustomer().getId());m.put("customerName",c.getCustomer().getFullName());m.put("subject",c.getSubject());m.put("message",c.getMessage());m.put("orderId",c.getOrderId());m.put("status",c.getStatus());m.put("resolution",c.getResolution());m.put("createdAt",c.getCreatedAt());return m;} }